@Composable
fun AppNavHost(navController: NavHostController) {
    NavHost(navController, startDestination = "home") {
        composable("home") { HomeRoute(onOpen = { id ->
            navController.navigate("job/$id")
        }) }
        composable("job/{id}") { entry ->
            JobRoute(id = requireNotNull(entry.arguments?.getString("id")))
        }
    }
}

sealed interface AppRoute {
    data object Home : AppRoute
    data class Job(val id: String) : AppRoute
}

@Composable
fun JobScreen(state: JobUiState, onBack: () -> Unit) {
    // UI thuần, không biết NavController
}

navController.navigate("main") {
    popUpTo("auth") { inclusive = true }
    launchSingleTop = true
}

navController.navigate(tabRoute) {
    popUpTo(navController.graph.startDestinationId) { saveState = true }
    launchSingleTop = true
    restoreState = true
}
